n                // Load schema from XML file\n                string path = GetBasePath(this) + "\\\\" + Export_SchemaFile;\n                if (System.IO.File.Exists(path))\n                {\n                    export.DataSet.Schema = DataSchema.LoadFromXml(this, path);\n                }\n                else\n                {\n                    ShowMessageBoxAsync(\n                        $"Schema file not found: {path}",\n                        DisplayName, MessageBoxImage.Information);\n\n                    // Create sample schema\n                    DataSchema schema = new DataSchema();\n                    schema.Append("BOB", ValueKind.Feature,\n                        new ChartObjectDescriptor()\n                        {\n                            Script = "ninZaBossOrderBlock",\n                            Map = new List<MapItem>()\n                            {\n                                new MapItem()\n                                    { Tool = DrawingTool.Text, Text = "\u25b2", Value = 1.0 },\n                                new MapItem()\n                                    { Tool = DrawingTool.Text, Text = "\u25bc", Value = -1.0 }\n                            }\n                        });\n\n                    schema.SaveToXml(path);\n\n                    ShowMessageBoxAsync(\n                        $"Sample schema has been created. Saved to file: {path}.",\n                        DisplayName, MessageBoxImage.Information);\n\n                    export.DataSet.Schema = schema;\n                }\n\n                Register(export);\n            }\n        }\n    }\n\n\n    #region Export\n    [Display(Name = "Schema file", GroupName = "Export", Order = 1)]\n    public string Export_SchemaFile { get; set; } = "schema.xml";\n\n    [Display(Name = "Temporality", GroupName = "Export", Order = 2)]\n    public ExportTemporality Export_Temporality { get; set; }\n        = ExportTemporality.Historical;\n\n    [Display(Name = "File", GroupName = "Export", Order = 3)]\n    public string Export_File { get; set; } = "";\n\n    [Display(Name = "Header", GroupName = "Export", Order = 4)]\n    public bool Export_Header { get; set; } = true;\n\n    [Display(Name = "Time", GroupName = "Export", Order = 5)]\n    public bool Export_Time { get; set; } = true;\n\n    [Display(Name = "Batch", GroupName = "Export", Order = 6)]\n    public bool Export_Batch { get; set; }\n\n    [Display(Name = "Delimiter", GroupName = "Export", Order = 7)]\n    public string Export_Delimiter { get; set; }\n    #endregion Export\n}\n'})}),"\n",(0,i.jsx)(t.h2,{id:"key-concepts",children:"Key Concepts"}),"\n",(0,i.jsx)(t.h3,{id:"chartobjectdescriptor",children:"ChartObjectDescriptor"}),"\n",(0,i.jsx)(t.p,{children:"Defines how to find and map a chart drawing object:"}),"\n",(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.th,{children:"Field"}),(0,i.jsx)(t.th,{children:"Description"})]})}),(0,i.jsxs)(t.tbody,{children:[(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:(0,i.jsx)(t.code,{children:"Script"})}),(0,i.jsxs)(t.td,{children:["NinjaScript indicator name that draws the objects (e.g., ",(0,i.jsx)(t.code,{children:'"ninZaBossOrderBlock"'}),")"]})]}),(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:(0,i.jsx)(t.code,{children:"Map"})}),(0,i.jsxs)(t.td,{children:["List of ",(0,i.jsx)(t.code,{children:"MapItem"})," rules that convert drawing object properties to numeric values"]})]})]})]}),"\n",(0,i.jsx)(t.h3,{id:"mapitem",children:"MapItem"}),"\n",(0,i.jsx)(t.p,{children:"Maps a drawing tool's visual properties to a numeric export value:"}),"\n",(0,i.jsxs)(t.table,{children:[(0,i.jsx)(t.thead,{children:(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.th,{children:"Field"}),(0,i.jsx)(t.th,{children:"Description"})]})}),(0,i.jsxs)(t.tbody,{children:[(0,i.jsxs)(t.tr,{children:[(0,i.jsx)(t.td,{children:(0,i.jsx)(t.code,{children:"Tool"})}),(0,i.jsxs)(t.td,{children:["The ",(0,i.jsx)(t.code,